CREATE SECURE VIEW HAVEN_STORE.ALIGN_ALYTICS.BREAK_SEGMENTATION_LOOKUP_HISTORY
( DATA_VERSION_ID, BREAKID, RESORT_NAME, SHIP_CODE, BREAK_TYPE, TARGET_FILL_BREAK_SEGMENT, LOOKUP, SOURCE_FILENAME, HASH_AGG_VAL )
AS SELECT DATA_VERSION_ID, BREAKID, RESORT_NAME, SHIP_CODE, BREAK_TYPE, TARGET_FILL_BREAK_SEGMENT, LOOKUP, SOURCE_FILENAME, HASH_AGG_VAL
FROM HAVEN_STORE.PRICER.BREAK_SEGMENTATION_LOOKUP_HISTORY;

CREATE SECURE VIEW HAVEN_STORE.ALIGN_ALYTICS.BUDGET_INPUTS_HISTORY
( DATA_VERSION_ID, HAVEN_SHIP_CODE, SEASON, BREAK_DATE, WEEK_DATE, BREAK_AND_HAVEN_CODE, OCC_CODE, PERIOD, ARRIVAL_DAY, HIREFLEET_BREAKS, LETTING_BREAKS, FINAL_BILLINGS, FINAL_BREAKS, WEEKS, UNIT_CONVERSION, BREAK_AND_OCC_CODE, UNIT_NO, SUN_UNITS, SUN_REV, DIRECT_UNITS, DIRECT_REV, SOURCE_FILENAME, HASH_AGG_VAL )
AS SELECT DATA_VERSION_ID, HAVEN_SHIP_CODE, SEASON, BREAK_DATE, WEEK_DATE, BREAK_AND_HAVEN_CODE, OCC_CODE, PERIOD, ARRIVAL_DAY, HIREFLEET_BREAKS, LETTING_BREAKS, FINAL_BILLINGS, FINAL_BREAKS, WEEKS, UNIT_CONVERSION, BREAK_AND_OCC_CODE, UNIT_NO, SUN_UNITS, SUN_REV, DIRECT_UNITS, DIRECT_REV, SOURCE_FILENAME, HASH_AGG_VAL
FROM HAVEN_STORE.PRICER.BUDGET_INPUTS_HISTORY;

CREATE SECURE VIEW HAVEN_STORE.ALIGN_ALYTICS.GRADE_MAPPING_ADDITIONAL
( PARK_CODE, OLD_GRADE, NEW_GRADE, MAPPED_GRADES )
AS SELECT PARK_CODE, OLD_GRADE, NEW_GRADE, MAPPED_GRADES
FROM HAVEN_BASE.PRICER.GRADE_MAPPING_ADDITIONAL;

CREATE SECURE VIEW HAVEN_STORE.ALIGN_ALYTICS.IMPORT_PUBLIC_HOLIDAYS
( HOL_DATE, DAY_OF_WEEK, HOLIDAY, SCOTLAND_FLAG, ENGLAND_WALES_FLAG, NON_RECURRING_FLAG )
AS SELECT HOL_DATE, DAY_OF_WEEK, HOLIDAY, SCOTLAND_FLAG, ENGLAND_WALES_FLAG, NON_RECURRING_FLAG
FROM HAVEN_BASE.PRICER.IMPORT_PUBLIC_HOLIDAYS;

CREATE SECURE VIEW HAVEN_STORE.ALIGN_ALYTICS.IMPORT_SCHOOL_HOLIDAYS
( SEASON_YEAR, DATE_FROM, DATE_TO, HOLIDAY_DESC, ENGLAND_WALES_FLAG, SCOTLAND_FLAG )
AS SELECT SEASON_YEAR, DATE_FROM, DATE_TO, HOLIDAY_DESC, ENGLAND_WALES_FLAG, SCOTLAND_FLAG
FROM HAVEN_BASE.PRICER.IMPORT_SCHOOL_HOLIDAYS;

CREATE SECURE VIEW HAVEN_STORE.ALIGN_ALYTICS.M01_BOOKING_CURVE_EBO_MODEL
( SEGMENT_SEASON, YEAR, NEXT_YEAR, PARK_CLUSTER, EBO_OFFSET_DAY, EBO_OFFSET_WEEK, EBO_UNPF_FCS_CM_GRO_UNCN, EBO_UNPF_FCS_DL_GRO_UNCN )
AS SELECT SEGMENT_SEASON, "YEAR", NEXT_YEAR, PARK_CLUSTER, EBO_OFFSET_DAY, EBO_OFFSET_WEEK, EBO_UNPF_FCS_CM_GRO_UNCN, EBO_UNPF_FCS_DL_GRO_UNCN
FROM HAVEN_BASE.PRICER.M01_BOOKING_CURVE_EBO_MODEL;

CREATE SECURE VIEW HAVEN_STORE.ALIGN_ALYTICS.M01_BOOKING_CURVE_MODEL
( PARK_CLUSTER, YEAR, SEGMENT_SEASON, SEASON_FORECAST_SEGMENT, BREAK_DOW, TIME_TO_OCCUPANCY, UNPF_FCS_CM_GRO_CONS )
AS SELECT PARK_CLUSTER, "YEAR", SEGMENT_SEASON, SEASON_FORECAST_SEGMENT, BREAK_DOW, TIME_TO_OCCUPANCY, UNPF_FCS_CM_GRO_CONS
FROM HAVEN_BASE.PRICER.M01_BOOKING_CURVE_MODEL;

CREATE SECURE VIEW HAVEN_STORE.ALIGN_ALYTICS.M06_CANCELLATIONS_DYNAMIC_UD
( BOOKING_DVTP_ID, CANCELLATION_DVTP_ID, AVG_DAYS_IN_PERIOD, UNITS_ACT_FN_GRO_CONS, UNIT_ACT_FN_CAN_CONS, SURVIVAL_RATE, LOG_SURVIVAL_RATE, LOG_SURVIVAL_RATE_DAILY )
AS SELECT BOOKING_DVTP_ID, CANCELLATION_DVTP_ID, AVG_DAYS_IN_PERIOD, UNITS_ACT_FN_GRO_CONS, UNIT_ACT_FN_CAN_CONS, SURVIVAL_RATE, LOG_SURVIVAL_RATE, LOG_SURVIVAL_RATE_DAILY
FROM HAVEN_BASE.PRICER.M06_CANCELLATIONS_DYNAMIC_UD;

CREATE SECURE VIEW HAVEN_STORE.ALIGN_ALYTICS.M06_CANCELLATIONS_STATIC_UD
( BOOKING_DVTP_ID, UNITS_ACTUAL_GRO_CONS, UNITS_ACTUAL_CAN_CONS, UNPC_FCS_FN_CAN_UNCN )
AS SELECT BOOKING_DVTP_ID, UNITS_ACTUAL_GRO_CONS, UNITS_ACTUAL_CAN_CONS, UNPC_FCS_FN_CAN_UNCN
FROM HAVEN_BASE.PRICER.M06_CANCELLATIONS_STATIC_UD;

CREATE SECURE VIEW HAVEN_STORE.ALIGN_ALYTICS.META_DVTP_GLOBAL_V2
( DVTP_L1_ID, DVTP_ID, TIMETOOCCUPANCY_FROM, TIMETOOCCUPANCY_TO, DVTP_LENGTH )
AS SELECT DVTP_L1_ID, DVTP_ID, TIMETOOCCUPANCY_FROM, TIMETOOCCUPANCY_TO, DVTP_LENGTH
