CREATE SECURE VIEW HAVEN_STORE.ALIGN_ALYTICS.UPLIFT_FACTORS_V5
( PARK_CODE, YEAR, _VERSION_BM, SEGMENT_SEASON, UPLIFT_FACTOR )
AS SELECT PARK_CODE, "YEAR", _VERSION_BM, SEGMENT_SEASON, UPLIFT_FACTOR
FROM HAVEN_BASE.PRICER.UPLIFT_FACTORS_V5;

CREATE SECURE VIEW HAVEN_STORE.ALIGN_ALYTICS.SHIP_LOOKUP
( OC_C_CODES, OC_C_LOCATION, HAVEN_CODE, SAME, SOURCE_FILENAME )
AS SELECT OC_C_CODES, OC_C_LOCATION, HAVEN_CODE, SAME, SOURCE_FILENAME
FROM HAVEN_PIPELINE.PX0006_BLUEYONDER_PRICER.SHIP_LOOKUP;

